// Validate sender and parse Telegram message into a dev-loop task
const msg = $input.first().json;
const message = msg.message || {};
const text = (message.text || '').trim();
const chatId = message.chat?.id;
const senderId = message.from?.id;
const senderName = message.from?.first_name || 'operator';

// Only accept messages from the configured operator chat
// n8n Cloud: hardcoded fallback (env access blocked)
const allowedChatId = typeof $env !== 'undefined' && $env.TELEGRAM_CHAT_ID ? $env.TELEGRAM_CHAT_ID : '8747048300';
if (allowedChatId && String(chatId) !== String(allowedChatId)) {
  return [{ json: { rejected: true, reason: 'unauthorized_chat', chatId } }];
}

// Ignore empty messages and commands that aren't tasks
if (!text || text.startsWith('/start') || text.startsWith('/help')) {
  return [{ json: {
    rejected: true,
    reason: text ? 'command' : 'empty',
    chatId,
    help_response: 'Send a plain text message describing a task. Example:\n\nAdd a formatPhoneNumber utility in packages/shared/src/ that normalizes US numbers to E.164'
  } }];
}

// Strip /task prefix if present
let taskText = text;
if (taskText.startsWith('/task ')) {
  taskText = taskText.substring(6).trim();
}

// Generate deterministic task_id from timestamp + short hash
const ts = Date.now();
const shortHash = ts.toString(36).slice(-6);
const taskId = `tg-${shortHash}`;

// Extract title: first line or first 60 chars
const firstLine = taskText.split('\n')[0];
const title = firstLine.length > 60 ? firstLine.substring(0, 57) + '...' : firstLine;

// Build TaskContract
const task = {
  task_id: taskId,
  title: title,
  goal: taskText,
  scope_boundaries: [],
  files_allowed: ['apps/api/**', 'packages/shared/**'],
  files_forbidden: [
    '**/auth/**', '**/billing/**', '**/stripe/**',
    '**/twilio/**', '**/oauth/**', '**/provisioning/**',
    '**/deploy/**', '**/migration/**'
  ],
  critical_systems_risk: false,
  expected_output: [],
  checks_required: ['typecheck']
};

return [{ json: {
  rejected: false,
  task,
  chatId,
  senderName,
  messageId: message.message_id
} }];

// Fast deterministic classifier: SIMPLE vs COMPLEX
const parsed = $input.first().json;
if (parsed.rejected) return [{ json: parsed }];

const task = parsed.task;
const text = (task.goal || '').toLowerCase();

// SIMPLE patterns: questions, status queries, listing requests
const SIMPLE_PATTERNS = [
  /^what (is|are|should|would)/,
  /^how (is|are|do|does|should|would|many|much)/,
  /^(show|list|check|tell|explain|describe|summarize|status|report)/,
  /^(which|where|when|who|why)/,
  /\?$/,
  /^(next|current|latest|recent|last) /,
  /priority|priorities|blocker|blockers|progress|status/,
  /what.*next/,
  /what.*important/,
  /what.*task/,
  /what.*blocker/,
  /what.*progress/,
  /how.*going/,
];

// COMPLEX patterns: implementation requests
const COMPLEX_PATTERNS = [
  /^(add|create|implement|build|write|fix|update|modify|change|refactor|remove|delete|rename)/,
  /^(deploy|migrate|install|configure|set up|wire|connect)/,
  /please (add|create|implement|build|write|fix|update)/,
  /need to (add|create|implement|build|write|fix|update)/,
];

let classification = 'COMPLEX'; // default to safe/full execution

// Check COMPLEX first (takes priority)
const isComplex = COMPLEX_PATTERNS.some(p => p.test(text));

if (!isComplex) {
  const isSimple = SIMPLE_PATTERNS.some(p => p.test(text));
  if (isSimple) classification = 'SIMPLE';
}

return [{ json: { ...parsed, classification } }];

// Fast response for SIMPLE queries — no Claude needed
const parsed = $input.first().json;
const task = parsed.task;

let answer = 'Task: ' + task.task_id + '\n';
answer += 'Type: Quick query (no execution needed)\n';
answer += 'Q: ' + task.title + '\n\n';
answer += 'This is a status/info question. ';
answer += 'Check the admin dashboard for current project state:\n';
answer += 'https://autoshopsmsai.com/admin\n\n';
answer += 'For tasks requiring code changes, rephrase as an action:\n';
answer += '"Add ...", "Fix ...", "Update ...", "Implement ..."';

return [{ json: {
  chatId: parsed.chatId,
  replyText: answer
} }];

const parsed = $('Parse Message into Task').first().json;
const task = parsed.task;
const title = task.title.length > 80 ? task.title.substring(0, 77) + '...' : task.title;
return [{ json: {
  chatId: parsed.chatId,
  replyText: 'Task received: ' + title + '\nAnalyzing...'
} }];

// Build final result message for Telegram
const parsed = $('Parse Message into Task').first().json;
const task = parsed.task;
const orchestratorResult = $input.first().json;

let status = 'submitted';
let decision = '';
if (orchestratorResult.review_packet) {
  const rp = orchestratorResult.review_packet;
  status = rp.goal_match === 'full' ? 'done' : rp.goal_match || 'processing';
  decision = rp.recommended_decision || '';
} else if (orchestratorResult.action) {
  decision = orchestratorResult.action;
  if (orchestratorResult.action === 'ESCALATE') status = 'escalated';
  else if (orchestratorResult.action === 'RETRY') status = 'retrying';
  else status = 'done';
} else if (orchestratorResult.error || orchestratorResult.statusCode >= 400) {
  status = 'failed (orchestrator error)';
}

let reply = `Task: ${task.task_id}\n`;
reply += `Title: ${task.title}\n`;
reply += `Status: ${status}\n`;
if (decision) reply += `Decision: ${decision}\n`;
if (orchestratorResult.review_packet?.branch) {
  reply += `Branch: ${orchestratorResult.review_packet.branch}\n`;
}

return [{ json: {
  chatId: parsed.chatId,
  replyText: reply
} }];

// Handle rejected messages (unauthorized chat, empty, /help)
const data = $input.first().json;

if (data.reason === 'command' || data.reason === 'empty') {
  return [{ json: {
    chatId: data.chatId,
    replyText: data.help_response || 'Send a plain text message describing a task.'
  } }];
}

// Unauthorized chat — do not respond (silent reject)
return [];
